-- ============================================================
-- ai-engineer-roadmap-sh-full-detailed-seed-v2-skill-conflict-fixed.sql
-- Full detailed AI Engineer roadmap seed based on roadmap.sh/ai-engineer.
-- Idempotent seed: safe to rerun in the same database/session.
-- ============================================================

-- Shared-skill aliases normalized against core/shared-skills.seed.sql.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

DELETE FROM public.progress_event WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('AI Engineer Roadmap', 'AI Engineer Roadmap - roadmap.sh Full Detailed Seed', 'AI Engineering Roadmap Full Detailed Seed'));
DELETE FROM public.user_node_progress WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('AI Engineer Roadmap', 'AI Engineer Roadmap - roadmap.sh Full Detailed Seed', 'AI Engineering Roadmap Full Detailed Seed'));
DELETE FROM public.roadmap_enrollment WHERE roadmap_version_id IN (SELECT rv.roadmap_version_id FROM public.roadmap_version rv JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('AI Engineer Roadmap', 'AI Engineer Roadmap - roadmap.sh Full Detailed Seed', 'AI Engineering Roadmap Full Detailed Seed'));
DELETE FROM public.roadmap WHERE title IN ('AI Engineer Roadmap', 'AI Engineer Roadmap - roadmap.sh Full Detailed Seed', 'AI Engineering Roadmap Full Detailed Seed');

    'AI Engineer',
    'ai-engineer',
    'AI engineer path covering practical AI product development, Python, ML foundations, LLMs, RAG, agents, evaluation, safety, LLMOps, deployment, observability, and portfolio-ready AI systems.',
    'Artificial Intelligence',
    true
) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, category = EXCLUDED.category, is_active = true, updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (SELECT career_role_id FROM public.career_role WHERE slug = 'ai-engineer'), inserted_roadmap AS (
    SELECT career_role_id, 'AI Engineer Roadmap', 'A structured learning path for becoming an AI engineer, covering practical AI product development, Python foundations, machine learning, deep learning, large language models, prompt engineering, retrieval-augmented generation, agents, evaluation, safety, LLMOps, deployment, observability, and portfolio-ready AI systems.', 'template', 'static', 'public' FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    SELECT roadmap_id, 1, 'published', 'AI Engineer Roadmap v1', 'A practical AI engineering roadmap that moves from foundations to production-ready AI applications through guided topics, checkpoints, optional practice projects, and required milestone projects.', 460, 'none', '{}'::jsonb, 'TB', 'custom', now() FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
) SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;
-- Upsert skills safely against both unique constraints: slug and name.
-- Some skills may already exist from other roadmap seeds with the same name but a different slug.
UPDATE public.skill s
SET
    name = ss.name,
    category = ss.category,
    description = ss.description,
    is_active = true,
    updated_at = now()
FROM seed_skill ss
WHERE s.slug = ss.slug;

UPDATE public.skill s
SET
    category = ss.category,
    description = ss.description,
    is_active = true,
    updated_at = now()
FROM seed_skill ss
WHERE s.name = ss.name
  AND NOT EXISTS (
      SELECT 1
      FROM public.skill existing_by_slug
      WHERE existing_by_slug.slug = ss.slug
  );

SELECT ss.name, ss.slug, ss.category, ss.description, true
FROM seed_skill ss
WHERE NOT EXISTS (
    SELECT 1
    FROM public.skill s
    WHERE s.slug = ss.slug OR s.name = ss.name
);

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY, title text NOT NULL, url text NOT NULL, resource_type text NOT NULL, description text NOT NULL, provider text, difficulty_level text) ON COMMIT DROP;

UPDATE public.learning_resource lr
SET
    title = sr.title,
    resource_type = sr.resource_type,
    description = sr.description,
    provider = sr.provider,
    difficulty_level = sr.difficulty_level,
    language_code = 'en',
    verification_status = 'verified',
    updated_at = now()
FROM (
    SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE lr.url = sr.url;

SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified'
FROM (
    SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE NOT EXISTS (SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url);

-- Roadmap nodes.
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (
    node_id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    node_key text UNIQUE NOT NULL,
    parent_key text,
    order_index int NOT NULL,
    node_type text NOT NULL,
    checkpoint_type text,
    selection_type text,
    required_count int,
    title text NOT NULL,
    description text,
    reason text,
    layout_role text NOT NULL,
    layout_group text,
    layout_rank int,
    layout_order int NOT NULL,
    estimated_hours int,
    difficulty_level text,
    priority int NOT NULL,
    position_x numeric(10,2),
    position_y numeric(10,2),
    metadata jsonb NOT NULL,
    is_required boolean NOT NULL,
    is_trackable boolean NOT NULL,
    learning_outcomes jsonb NOT NULL,
    completion_criteria jsonb NOT NULL
) ON COMMIT DROP;


SELECT m.roadmap_version_id, NULL, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.reason, sn.order_index, sn.layout_role, sn.layout_group, sn.layout_rank, sn.layout_order, sn.estimated_hours, sn.difficulty_level, sn.priority, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria
FROM seed_node sn CROSS JOIN seed_roadmap_map m
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    reason = EXCLUDED.reason,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    layout_group = EXCLUDED.layout_group,
    layout_rank = EXCLUDED.layout_rank,
    layout_order = EXCLUDED.layout_order,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    priority = EXCLUDED.priority,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

UPDATE public.roadmap_node child
SET parent_node_id = parent.roadmap_node_id
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node parent ON parent.roadmap_version_id = m.roadmap_version_id AND parent.slug = sn.parent_key
WHERE child.roadmap_version_id = m.roadmap_version_id
  AND child.slug = sn.node_key
  AND sn.parent_key IS NOT NULL;

UPDATE public.roadmap_node child
SET parent_node_id = NULL
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
WHERE child.roadmap_version_id = m.roadmap_version_id
  AND child.slug = sn.node_key
  AND sn.parent_key IS NULL;

-- Node-skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (node_key text NOT NULL, skill_slug text NOT NULL, PRIMARY KEY (node_key, skill_slug)) ON COMMIT DROP;

DELETE FROM public.roadmap_node_skill rns
USING seed_roadmap_map m, public.roadmap_node rn
WHERE rn.roadmap_version_id = m.roadmap_version_id
  AND rns.roadmap_node_id = rn.roadmap_node_id;

SELECT rn.roadmap_node_id, s.skill_id
FROM seed_node_skill sns
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node rn ON rn.roadmap_version_id = m.roadmap_version_id AND rn.slug = sns.node_key
JOIN seed_skill ss ON ss.slug = sns.skill_slug
JOIN LATERAL (
    SELECT skill_id
    FROM public.skill s
    WHERE s.slug = ss.slug OR s.name = ss.name
    ORDER BY CASE WHEN s.slug = ss.slug THEN 0 ELSE 1 END
    LIMIT 1
) s ON true
ON CONFLICT (roadmap_node_id, skill_id) DO NOTHING;

-- Node-resource mappings.
DROP TABLE IF EXISTS seed_node_resource;
CREATE TEMP TABLE seed_node_resource (node_key text NOT NULL, resource_key text NOT NULL, order_index int NOT NULL, is_primary boolean NOT NULL, PRIMARY KEY (node_key, resource_key)) ON COMMIT DROP;

DELETE FROM public.roadmap_node_resource rnr
USING seed_roadmap_map m, public.roadmap_node rn
WHERE rn.roadmap_version_id = m.roadmap_version_id
  AND rnr.roadmap_node_id = rn.roadmap_node_id;

SELECT rn.roadmap_node_id, lr.learning_resource_id, snr.order_index, snr.is_primary
FROM seed_node_resource snr
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node rn ON rn.roadmap_version_id = m.roadmap_version_id AND rn.slug = snr.node_key
JOIN seed_resource sr ON sr.resource_key = snr.resource_key
JOIN public.learning_resource lr ON lr.url = sr.url
ON CONFLICT (roadmap_node_id, learning_resource_id) DO UPDATE SET order_index = EXCLUDED.order_index, is_primary = EXCLUDED.is_primary;

SELECT DISTINCT lr.learning_resource_id, s.skill_id
FROM seed_node_resource snr
JOIN seed_node_skill sns ON sns.node_key = snr.node_key
JOIN seed_resource sr ON sr.resource_key = snr.resource_key
JOIN public.learning_resource lr ON lr.url = sr.url
JOIN seed_skill ss ON ss.slug = sns.skill_slug
JOIN LATERAL (
    SELECT skill_id
    FROM public.skill s
    WHERE s.slug = ss.slug OR s.name = ss.name
    ORDER BY CASE WHEN s.slug = ss.slug THEN 0 ELSE 1 END
    LIMIT 1
) s ON true
ON CONFLICT (learning_resource_id, skill_id) DO NOTHING;

-- Edges.
-- Visual edge rules: sequence, contains, choice render by default; dependency, unlock, recommendation are logic/hints and hidden by default.
DROP TABLE IF EXISTS seed_edge;
CREATE TEMP TABLE seed_edge (from_key text NOT NULL, to_key text NOT NULL, edge_type text NOT NULL, dependency_type text NOT NULL, condition jsonb NOT NULL) ON COMMIT DROP;

DELETE FROM public.roadmap_edge e
USING seed_roadmap_map m
WHERE e.roadmap_version_id = m.roadmap_version_id;

SELECT m.roadmap_version_id, source.roadmap_node_id, target.roadmap_node_id, se.edge_type, se.dependency_type, se.condition
FROM seed_edge se
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node source ON source.roadmap_version_id = m.roadmap_version_id AND source.slug = se.from_key
JOIN public.roadmap_node target ON target.roadmap_version_id = m.roadmap_version_id AND target.slug = se.to_key
ON CONFLICT (roadmap_version_id, from_node_id, to_node_id, edge_type) DO UPDATE SET dependency_type = EXCLUDED.dependency_type, condition = EXCLUDED.condition;


-- Summary check.
DO $$
DECLARE
    skill_count int;
    resource_count int;
    node_count int;
    node_skill_count int;
    node_resource_count int;
    edge_count int;
    required_trackable_hours int;
    all_trackable_hours int;
BEGIN
    SELECT COUNT(*) INTO skill_count FROM seed_skill;
    SELECT COUNT(*) INTO resource_count FROM seed_resource;
    SELECT COUNT(*) INTO node_count FROM seed_node;
    SELECT COUNT(*) INTO node_skill_count FROM seed_node_skill;
    SELECT COUNT(*) INTO node_resource_count FROM seed_node_resource;
    SELECT COUNT(*) INTO edge_count FROM seed_edge;
    SELECT COALESCE(SUM(estimated_hours), 0) INTO required_trackable_hours FROM seed_node WHERE is_required = true AND is_trackable = true;
    SELECT COALESCE(SUM(estimated_hours), 0) INTO all_trackable_hours FROM seed_node WHERE is_trackable = true;

    RAISE NOTICE 'AI Engineer seed complete. Skills: %, Resources: %, Nodes: %, NodeSkills: %, NodeResources: %, Edges: %, RequiredTrackableHours: %, AllTrackableHours: %, RoadmapEstimatedHours: %', skill_count, resource_count, node_count, node_skill_count, node_resource_count, edge_count, required_trackable_hours, all_trackable_hours, 460;
END $$;

COMMIT;
